    seoKeywords: ["wedding wishes", "wedding message", "wedding card message", "wedding congratulations", "wedding wishes for friend", "marriage wishes", "wedding greetings", "best wedding wishes", "short wedding message", "wedding card quotes"],
    excerpt: "Wedding wishes should match your relationship with the couple. Use this simple guide to avoid awkward or generic messages.",
    date: "March 31, 2026",
